import '../lib/daily_window.dart';
import '../lib/offset_schedule.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final transition = DateTime.utc(2026, 3, 8, 10);
  final scheduler = DailyWindowScheduler(
    OffsetSchedule(const Duration(hours: -8), <OffsetChange>[
      OffsetChange(transition, const Duration(hours: -7)),
    ]),
  );

  check(
    scheduler.nextRun(DateTime.utc(2026, 3, 7, 20), hour: 3, minute: 0) ==
        transition,
    'a wall-clock target created by the jump resolves to the transition instant',
  );

  print('final tests passed');
}
